                rows.push(['?붿빟', '?щ쭩', String(data.summary.totalDeaths)]);
                rows.push(['?붿빟', '遺??, String(data.summary.totalInjuries)]);
                rows.push(['?붿빟', '?ъ궛?쇳빐', String(data.summary.totalPropertyDamage)]);
                data.bySido.forEach(d => rows.push(['?쒕룄蹂?, d.name, String(d.count)]));
                data.byFireType.forEach(d => rows.push(['?붿옱?좏삎', d.name, String(d.count)]));
                data.byPlace.forEach(d => rows.push(['?μ냼蹂?, d.name, String(d.count)]));
                data.byCause.forEach(d => rows.push(['諛쒗솕?붿씤', d.name, String(d.count)]));
                data.byMonth.forEach(d => rows.push(['?붾퀎', d.month, String(d.count)]));
                data.casualtiesBySido.forEach(d => rows.push(['?몃챸?쇳빐', d.name, `?щ쭩${d.deaths}/遺??{d.injuries}`]));
                const csv = '\uFEFF' + rows.map(r => r.join(',')).join('\n');
                const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
                const a = document.createElement('a');
                a.href = URL.createObjectURL(blob);
                a.download = `?붿옱?듦퀎_${year}??csv`;
                a.click();
              }}
              className="flex items-center gap-2 px-4 py-2 bg-secondary text-on-secondary rounded-xl text-sm font-bold hover:bg-secondary/90 transition-colors"
            >
              <span className="material-symbols-outlined text-lg">download</span>
              CSV
            </button>
          )}
        </div>
      </div>

      {/* Loading */}
      {loading && (
