          <div className="w-10 h-10 border-3 border-primary/30 border-t-primary rounded-full animate-spin" />
          <div className="text-sm text-on-surface-variant">
            <span className="font-bold text-primary">{year}??/span> ?붿옱?듦퀎 ?곗씠??吏묎퀎 以?..
          </div>
          <p className="text-xs text-on-surface-variant/60">????곗씠??泥섎━濡?理쒕? 30珥??뚯슂?????덉뒿?덈떎</p>
        </div>
      )}

      {/* Error */}
      {error && !loading && (
        <div className="p-6 rounded-2xl bg-error/10 border border-error/30">
          <div className="flex items-start gap-3">
            <span className="material-symbols-outlined text-error text-2xl mt-0.5">cloud_off</span>
            <div className="flex-1">
              <h3 className="font-bold text-error text-lg">?곌컙?붿옱?듦퀎 API ?곌껐 ?ㅽ뙣</h3>
              <p className="text-sm text-on-surface-variant mt-1">{error}</p>
              <p className="text-xs text-on-surface-variant/60 mt-2">
                API ?쒕퉬???뱀씤 ?湲?以묒씠嫄곕굹 怨듦났?곗씠???쒕쾭 ?먭? 以묒엯?덈떎.
              </p>
              <button
                onClick={() => setYear(y => y)}
                className="mt-4 flex items-center gap-2 px-4 py-2 bg-error/20 text-error rounded-xl text-sm font-bold hover:bg-error/30 transition-colors"
              >
                <span className="material-symbols-outlined text-base">refresh</span>
                ?ㅼ떆 ?쒕룄
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Data Display */}
      {data && !loading && (
        <>
          {/* Summary Cards */}
          <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
            {[
              { label: '珥??붿옱 嫄댁닔', value: formatNumber(data.summary.totalFires), icon: 'local_fire_department', color: 'text-error' },
              { label: '?щ쭩', value: `${data.summary.totalDeaths}紐?, icon: 'person_off', color: 'text-error' },
              { label: '遺??, value: `${data.summary.totalInjuries}紐?, icon: 'personal_injury', color: 'text-tertiary' },
              { label: '?몃챸?쇳빐 ?⑷퀎', value: `${data.summary.totalCasualties}紐?, icon: 'group', color: 'text-on-surface' },
              { label: '?ъ궛?쇳빐', value: `${formatNumber(data.summary.totalPropertyDamage)}??, icon: 'payments', color: 'text-primary' },
            ].map(card => (
              <div key={card.label} className="bg-surface-container rounded-2xl p-4 border border-outline-variant/10">
                <div className="flex items-center gap-2 mb-2">
                  <span className={`material-symbols-outlined ${card.color} text-lg`} style={{ fontVariationSettings: "'FILL' 1" }}>{card.icon}</span>
                  <span className="text-[10px] text-on-surface-variant font-bold uppercase">{card.label}</span>
                </div>
                <p className="text-2xl font-extrabold text-on-surface font-headline">{card.value}</p>
              </div>
            ))}
          </div>

          {/* Charts Grid */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            {/* ?쒕룄蹂??붿옱 嫄댁닔 */}
