import { useRef, useEffect, useState } from 'react';
import type { FireFacility } from '../data/mockData';
import { loadKakaoMapSDK, retryKakaoLoad } from '../utils/kakaoLoader';

// ?꾩떆蹂?以묒떖 醫뚰몴
const CITY_CENTERS: Record<string, { lat: number; lng: number }> = {
  seoul: { lat: 37.5665, lng: 126.978 },
  busan: { lat: 35.1796, lng: 129.0756 },
  daegu: { lat: 35.8714, lng: 128.6014 },
  incheon: { lat: 37.4563, lng: 126.7052 },
  gwangju: { lat: 35.1595, lng: 126.8526 },
  daejeon: { lat: 36.3504, lng: 127.3845 },
  ulsan: { lat: 35.5384, lng: 129.3114 },
  sejong: { lat: 36.48, lng: 127.0 },
  jeju: { lat: 33.4996, lng: 126.5312 },
};

// ?곹깭蹂?留덉빱 ?됱긽
const STATUS_COLORS: Record<string, string> = {
  '?뺤긽': '#34d399',
  '?먭??꾩슂': '#fbbf24',
  '怨좎옣': '#ef4444',
};

interface KakaoMapProps {
  data: FireFacility[];
  city: string;
  height?: string;
  selectedId?: string | null;
}

declare global {
  interface Window {
    kakao: any;
  }
}

export default function KakaoMap({ data, city, height = '300px', selectedId }: KakaoMapProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any>(null);
  const clustererRef = useRef<any>(null);
  const markersRef = useRef<Map<string, any>>(new Map());
  const overlaysRef = useRef<Map<string, any>>(new Map());
  const [sdkReady, setSdkReady] = useState(!!window.kakao?.maps);
  const [sdkError, setSdkError] = useState('');

  // SDK ?숈쟻 濡쒕뱶
  useEffect(() => {
    if (sdkReady) return;
    loadKakaoMapSDK()
      .then(() => setSdkReady(true))
      .catch(err => setSdkError(err.message));
  }, [sdkReady]);

  // 吏??珥덇린??(SDK 濡쒕뱶 ?꾨즺 ??
  useEffect(() => {
    if (!sdkReady || !containerRef.current || !window.kakao?.maps) return;

    const center = CITY_CENTERS[city] || CITY_CENTERS.seoul;
    const options = {
      center: new window.kakao.maps.LatLng(center.lat, center.lng),
      level: 7,
    };

    const map = new window.kakao.maps.Map(containerRef.current, options);
    mapRef.current = map;

    // 以?而⑦듃濡?r
    const zoomControl = new window.kakao.maps.ZoomControl();
    map.addControl(zoomControl, window.kakao.maps.ControlPosition.RIGHT);

    // 留덉빱 ?대윭?ㅽ꽣??珥덇린??r
    const clusterer = new window.kakao.maps.MarkerClusterer({
      map: map,
      averageCenter: true,
      minLevel: 7,
      disableClickZoom: false,
      styles: [{
        width: '40px', height: '40px',
        background: 'rgba(239, 68, 68, 0.9)',
        borderRadius: '50%',
        color: '#fff',
        textAlign: 'center',
        fontWeight: 'bold',
        lineHeight: '40px',
        fontSize: '14px',
        border: '2px solid rgba(255,255,255,0.5)',
        boxShadow: '0 4px 12px rgba(239,68,68,0.3)'
      }]
    });
    clustererRef.current = clusterer;

    return () => {
      clustererRef.current?.clear();
      markersRef.current = new Map();
      overlaysRef.current = new Map();
    };
  }, [sdkReady]);

  // ?꾩떆 蹂寃???以묒떖 ?대룞
  useEffect(() => {
    if (!mapRef.current) return;
    const center = CITY_CENTERS[city] || CITY_CENTERS.seoul;
    mapRef.current.setCenter(new window.kakao.maps.LatLng(center.lat, center.lng));
  }, [city]);

  // 留덉빱 ?뚮뜑留?r
  useEffect(() => {
    if (!mapRef.current || !window.kakao?.maps) return;
    const map = mapRef.current;

    // 湲곗〈 留덉빱/?ㅻ쾭?덉씠 ?쒓굅
    clustererRef.current?.clear();
    markersRef.current.forEach(m => m.setMap(null));
    overlaysRef.current.forEach(o => o.setMap(null));
    markersRef.current = new Map();
    overlaysRef.current = new Map();

    const newMarkers: any[] = [];

    data.forEach(item => {
      const position = new window.kakao.maps.LatLng(item.lat, item.lng);
      const color = STATUS_COLORS[item.status] || '#9ca3af';

      // SVG 留덉빱 ?대?吏
      const markerSize = new window.kakao.maps.Size(24, 35);
      const svgContent = `
        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="35" viewBox="0 0 24 35">
          <path d="M12 0C5.4 0 0 5.4 0 12c0 9 12 23 12 23s12-14 12-23C24 5.4 18.6 0 12 0z" fill="${color}"/>
          <circle cx="12" cy="12" r="5" fill="white" opacity="0.9"/>
        </svg>
      `;
      const blob = new Blob([svgContent], { type: 'image/svg+xml' });
      const url = URL.createObjectURL(blob);
      const markerImage = new window.kakao.maps.MarkerImage(url, markerSize);

      const marker = new window.kakao.maps.Marker({
        map,
        position,
        image: markerImage,
        title: item.id,
      });

      // 而ㅼ뒪? ?ㅻ쾭?덉씠 (?대┃ ???쒖떆)
      const overlayContent = `
        <div style="
          background: #0f1629;
          border: 1px solid ${color}40;
          border-radius: 12px;
          padding: 12px 16px;
          box-shadow: 0 8px 32px rgba(0,0,0,0.5);
          min-width: 200px;
          font-family: 'Inter', sans-serif;
          position: relative;
        ">
          <div style="display: flex; align-items: center; gap: 8px; margin-bottom: 8px;">
            <span style="
              display: inline-block;
              width: 8px; height: 8px;
              border-radius: 50%;
              background: ${color};
              ${item.status === '怨좎옣' ? 'animation: pulse 1.5s infinite;' : ''}
            "></span>
            <span style="color: #e5e7eb; font-weight: 800; font-size: 14px;">${item.id}</span>
            <span style="
              font-size: 10px;
              padding: 2px 8px;
              border-radius: 9999px;
              background: ${color}20;
              color: ${color};
              font-weight: 700;
              border: 1px solid ${color}40;
            ">${item.status}</span>
          </div>
          <p style="color: #9ca3af; font-size: 11px; margin: 0 0 4px;">${item.type}</p>
          <p style="color: #e5e7eb; font-size: 12px; margin: 0; line-height: 1.4;">${item.address}</p>
          <div style="
            position: absolute;
            bottom: -8px; left: 50%;
            transform: translateX(-50%);
            width: 0; height: 0;
            border-left: 8px solid transparent;
            border-right: 8px solid transparent;
            border-top: 8px solid #0f1629;
          "></div>
        </div>
      `;

      const overlay = new window.kakao.maps.CustomOverlay({
        content: overlayContent,
        position,
        yAnchor: 1.5,
        zIndex: 10,
      });

      // ?대┃ ?좉?
      window.kakao.maps.event.addListener(marker, 'click', () => {
        // ?ㅻⅨ ?ㅻ쾭?덉씠 紐⑤몢 ?リ린
        overlaysRef.current.forEach(o => o.setMap(null));
        overlay.setMap(map);
        map.panTo(position);
      });

      markersRef.current.set(item.id, marker);
      overlaysRef.current.set(item.id, overlay);
      newMarkers.push(marker);
    });

    if (clustererRef.current) {
      clustererRef.current.addMarkers(newMarkers);
    }

    // Bounds 留욎텛湲?(?곗씠?곌? ?덉쓣 ??
    if (data.length > 0) {
      const bounds = new window.kakao.maps.LatLngBounds();
      data.forEach(item => {
        bounds.extend(new window.kakao.maps.LatLng(item.lat, item.lng));
      });
      map.setBounds(bounds);
    }
  }, [data, city]);

  // ?몃??먯꽌 selectedId 蹂寃????대떦 留덉빱 ?ъ빱??r
  useEffect(() => {
    if (!selectedId || !mapRef.current) return;

    const overlay = overlaysRef.current.get(selectedId);
    const marker = markersRef.current.get(selectedId);
    if (!overlay || !marker) return;

    // ?ㅻⅨ ?ㅻ쾭?덉씠 ?リ린
    overlaysRef.current.forEach(o => o.setMap(null));
    // ?대떦 留덉빱???ㅻ쾭?덉씠 ?쒖떆 + ?대룞
    overlay.setMap(mapRef.current);
    mapRef.current.panTo(marker.getPosition());
  }, [selectedId]);

  // SDK ?먮윭 ??UI
  if (sdkError) {
    return (
      <div style={{ width: '100%', height }} className="rounded-xl overflow-hidden bg-surface-container flex items-center justify-center">
        <div className="text-center p-6">
          <span className="material-symbols-outlined text-error text-3xl">map</span>
          <p className="text-sm text-on-surface-variant mt-2">移댁뭅?ㅻ㏊ SDK 濡쒕뱶 ?ㅽ뙣</p>
          <p className="text-xs text-on-surface-variant/60 mt-1">{sdkError}</p>
          <button
            onClick={() => { setSdkError(''); retryKakaoLoad().then(() => setSdkReady(true)).catch(e => setSdkError(e.message)); }}
            className="mt-3 px-4 py-1.5 text-xs font-bold bg-primary text-on-primary rounded-lg hover:bg-primary/90 transition-colors"
          >
            ?ъ떆??r
          </button>
        </div>
      </div>
    );
  }

  if (!sdkReady) {
    return (
      <div style={{ width: '100%', height }} className="rounded-xl overflow-hidden bg-surface-container flex items-center justify-center">
        <div className="animate-spin w-6 h-6 border-2 border-primary border-t-transparent rounded-full"></div>
        <span className="ml-2 text-xs text-on-surface-variant">移댁뭅?ㅻ㏊ 濡쒕뵫 以?..</span>
      </div>
    );
  }

  return (
    <div
      ref={containerRef}
      style={{ width: '100%', height }}
      className="rounded-xl overflow-hidden"
    />
  );
}

