                  <p className="text-xs text-on-surface-variant">?곗씠??媛깆떊 二쇨린</p>
                </div>
                <select 
                  value={refreshInterval}
                  onChange={e => setRefreshInterval(e.target.value)}
                  className="bg-surface-container-high text-on-surface text-sm rounded-lg px-2 py-1.5 border border-outline-variant/20 focus:outline-none focus:border-primary"
                >
                  <option value="1">1遺꾨쭏??/option>
                  <option value="5">5遺꾨쭏??/option>
                  <option value="10">10遺꾨쭏??/option>
                  <option value="0">?섎룞 媛깆떊</option>
                </select>
