function humanizeApiError(status: number, body: string): string {
  if (status === 502) return 'API ?쒕퉬???뱀씤 ?湲?以묒씠嫄곕굹 怨듦났?곗씠???쒕쾭 ?먭? 以묒엯?덈떎.';
